     8|
     9|interface Props {
    10|  params: Promise<{ slug: string }>;
    11|  searchParams: Promise<{ sort?: string; level?: string; min?: string; max?: string }>;
    12|}
    13|
    14|export async function generateMetadata({ params }: Props): Promise<Metadata> {
    15|  const { slug } = await params;
    16|  const supabase = await createClient();
    17|  const { data: category } = await supabase
    18|    .from('categories')
    19|    .select('name, description')
    20|    .eq('slug', slug)
