    22|
    23|  if (!category) return { title: 'Categoría no encontrada' };
    24|  const cat = category as unknown as { name: string; description: string | null };
    25|
    26|  return {
    27|    title: `${cat.name} | Fun4Me Store`,
    28|    description: cat.description || `Explorá nuestra colección de ${cat.name}`,
    29|  };
    30|}
    31|
    32|export default async function CategoryPage({ params, searchParams }: Props) {
    33|  const { slug } = await params;
    34|  const sp = await searchParams;
    35|  const supabase = await createClient();
    36|
    37|  const { data: category } = await supabase
    38|    .from('categories')
    39|    .select('*')
    40|    .eq('slug', slug)
    41|    .single();
    42|
    43|  if (!category) notFound();
    44|  const cat = category as unknown as ExtendedCategory;
    45|
    46|  let query = supabase
    47|    .from('products')
    48|    .select('*, categories(slug)')
    49|    .eq('category_id', cat.id)
    50|    .eq('is_active', true);
    51|
    52|  if (sp.level) {
    53|    query = query.eq('experience_level' as string, sp.level);
    54|  }
    55|  if (sp.min) {
    56|    query = query.gte('price', parseInt(sp.min));
    57|  }
    58|  if (sp.max) {
    59|    query = query.lte('price', parseInt(sp.max));
    60|  }
    61|
    62|  switch (sp.sort) {
    63|    case 'price_asc':
    64|      query = query.order('price', { ascending: true });
    65|      break;
    66|    case 'price_desc':
    67|      query = query.order('price', { ascending: false });
    68|      break;
    69|    case 'newest':
    70|      query = query.order('created_at', { ascending: false });
    71|      break;
    72|    default:
    73|      query = query.order('is_featured', { ascending: false }).order('created_at', { ascending: false });
    74|  }
    75|
    76|  const { data: products } = await query;
    77|  const items = (products || []) as unknown as (ExtendedProduct & { categories: { slug: string } | null })[];
    78|
    79|  return (
    80|    <div className="container mx-auto px-4 py-8">
    81|      {/* Breadcrumbs */}
    82|      <nav className="mb-6 flex items-center gap-2 text-sm text-muted-foreground">
    83|        <Link href="/" className="hover:text-foreground">Inicio</Link>
    84|        <span>/</span>
    85|        <span className="text-foreground">{cat.name}</span>
    86|      </nav>
    87|
    88|      <div className="mb-8">
    89|        <h1 className="text-3xl font-bold">{cat.name}</h1>
    90|        {cat.description && (
    91|          <p className="mt-2 text-muted-foreground">{cat.description}</p>
    92|        )}
    93|        <p className="mt-1 text-sm text-muted-foreground">{items.length} productos</p>
    94|      </div>
    95|
    96|      <div className="flex flex-col gap-8 lg:flex-row">
    97|        {/* Filters Sidebar */}
    98|        <aside className="w-full shrink-0 lg:w-64">
    99|          <CategoryFilters slug={slug} currentParams={sp} />
   100|        </aside>
   101|
   102|        {/* Product Grid */}
   103|        <div className="flex-1">
   104|          {items.length > 0 ? (
   105|            <div className="grid grid-cols-2 gap-4 sm:grid-cols-2 lg:grid-cols-3">
   106|              {items.map((product) => (
   107|                <ProductCard
   108|                  key={product.id}
   109|                  product={{
   110|                    ...product,
   111|                    category_slug: product.categories?.slug || slug,
   112|                  }}
   113|                />
   114|              ))}
   115|            </div>
   116|          ) : (
   117|            <div className="flex flex-col items-center justify-center py-20 text-center">
   118|              <span className="mb-4 text-2xl font-semibold text-muted-foreground">Sin resultados</span>
   119|              <h2 className="text-xl font-semibold">No encontramos productos</h2>
   120|              <p className="mt-2 text-muted-foreground">Intentá con otros filtros o explorá otras categorías.</p>
   121|            </div>
   122|          )}
   123|        </div>
   124|      </div>
   125|    </div>
   126|  );
   127|}
