   100|          </p>
   101|        </div>
   102|      </div>
   103|
   104|      <p className="mb-6 text-sm text-muted-foreground">{products.length} productos</p>
   105|
   106|      {/* Product Grid */}
   107|      {products.length > 0 ? (
   108|        <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 lg:grid-cols-4">
   109|          {products.map((product) => (
   110|            <ProductCard
