     7|import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
     8|
     9|function AgeVerificationForm() {
    10|  const router = useRouter();
    11|  const searchParams = useSearchParams();
    12|  const redirect = searchParams.get('redirect') || '/';
    13|  const [day, setDay] = useState('');
    14|  const [month, setMonth] = useState('');
    15|  const [year, setYear] = useState('');
    16|  const [error, setError] = useState('');
    17|
    18|  function handleVerify() {
    19|    setError('');
    20|    const d = parseInt(day, 10);
    21|    const m = parseInt(month, 10);
    22|    const y = parseInt(year, 10);
    23|
    24|    if (!d || !m || !y || d < 1 || d > 31 || m < 1 || m > 12 || y < 1900 || y > 2100) {
    25|      setError('Por favor ingresá una fecha válida.');
    26|      return;
    27|    }
    28|
    29|    const birthDate = new Date(y, m - 1, d);
    30|    const today = new Date();
    31|    let age = today.getFullYear() - birthDate.getFullYear();
    32|    const monthDiff = today.getMonth() - birthDate.getMonth();
    33|    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
    34|      age--;
    35|    }
    36|
    37|    if (age < 18) {
    38|      setError('Debés ser mayor de 18 años para acceder a este sitio.');
    39|      return;
    40|    }
    41|
    42|    const expires = new Date();
    43|    expires.setDate(expires.getDate() + 30);
    44|    document.cookie = `age-verified=true; expires=${expires.toUTCString()}; path=/; SameSite=Lax`;
    45|
    46|    router.push(redirect);
    47|  }
    48|
    49|  return (
    50|    <Card className="w-full max-w-md">
    51|      <CardHeader className="text-center">
    52|        <div className="mx-auto mb-4 text-2xl font-bold text-red-500">+18</div>
    53|        <CardTitle className="text-2xl">Verificación de Edad</CardTitle>
    54|        <CardDescription>
    55|          Confirma que sos mayor de 18 años para acceder a Fun4Me Store
    56|        </CardDescription>
    57|      </CardHeader>
    58|      <CardContent className="space-y-6">
    59|        <p className="text-center text-sm text-muted-foreground">
    60|          Este sitio contiene productos para adultos. Ingresá tu fecha de nacimiento para continuar.
    61|        </p>
    62|
    63|        <div className="grid grid-cols-3 gap-3">
    64|          <div>
    65|            <label className="mb-1 block text-xs text-muted-foreground">Día</label>
    66|            <Input
    67|              type="number"
    68|              placeholder="DD"
    69|              min="1"
    70|              max="31"
    71|              value={day}
    72|              onChange={(e) => setDay(e.target.value)}
    73|              className="text-center"
    74|            />
    75|          </div>
    76|          <div>
    77|            <label className="mb-1 block text-xs text-muted-foreground">Mes</label>
    78|            <Input
    79|              type="number"
    80|              placeholder="MM"
    81|              min="1"
    82|              max="12"
    83|              value={month}
    84|              onChange={(e) => setMonth(e.target.value)}
    85|              className="text-center"
    86|            />
    87|          </div>
    88|          <div>
    89|            <label className="mb-1 block text-xs text-muted-foreground">Año</label>
    90|            <Input
    91|              type="number"
    92|              placeholder="AAAA"
    93|              min="1900"
    94|              max="2100"
    95|              value={year}
    96|              onChange={(e) => setYear(e.target.value)}
    97|              className="text-center"
    98|            />
    99|          </div>
   100|        </div>
   101|
   102|        {error && (
   103|          <p className="text-center text-sm text-red-500">{error}</p>
   104|        )}
   105|
   106|        <Button
   107|          onClick={handleVerify}
   108|          className="w-full bg-gradient-to-r from-rose-500 to-purple-600 text-white hover:from-rose-600 hover:to-purple-700"
