   113|
   114|        <p className="text-center text-xs text-muted-foreground">
   115|          Al ingresar, confirmás que tenés la edad legal para ver contenido para adultos en Paraguay.
   116|        </p>
   117|      </CardContent>
   118|    </Card>
   119|  );
   120|}
